    function rebuildSubgroups(node, specs, bucketFn){
      var sectionMap = collectSectionsFromSubtree(node);
      var sectionOrder = ["完成セット","ベース","カスタマイズ","設定","クオリティセット","実クオリティ項目"];
      var groups = specs.map(function(spec){ return { title_ja: spec.title_ja, title_en: spec.title_en, children: [] }; });
      for (var s=0;s<sectionOrder.length;s++) {
        var title = sectionOrder[s];
        var items = sectionMap[title] || [];
        for (var g=0; g<groups.length; g++) {
          var picked = [];
          for (var i=0;i<items.length;i++) {
            var item = items[i];
            if (bucketFn(String(item.id||"")) === specs[g].key) picked.push(clone(item));
          }
          if (picked.length) groups[g].children.push({ title_ja: title, title_en: title, children: picked });
        }
      }
      node.children = groups.filter(function(g){ return g.children && g.children.length; });
    }

