    var QILIN_TITLE_JA = '🦌 麒麟特化コレクション';
    var QILIN_TITLE_EN = 'Qilin Special Collection';

    function isArray(v){ return Object.prototype.toString.call(v) === '[object Array]'; }
    function isObj(v){ return !!v && typeof v === 'object' && !isArray(v); }
    function clone(v){ return JSON.parse(JSON.stringify(v)); }
    function titleOf(node){ return node && (node.title_ja || node.titleJa || node.label || node.title || ''); }
    function findByTitle(node, title){
      if (!node) return null;
      if (isArray(node)) {
        for (var i = 0; i < node.length; i++) {
          var got = findByTitle(node[i], title);
          if (got) return got;
        }
        return null;
      }
      if (isObj(node)) {
        if (titleOf(node) === title) return node;
        var keys = Object.keys(node);
        for (var j = 0; j < keys.length; j++) {
          var got2 = findByTitle(node[keys[j]], title);
          if (got2) return got2;
        }
      }
      return null;
    }
