    var QILIN_TITLE_JA = '🦌 麒麟特化コレクション';
    var SEA_TITLE_JA = '🌊 海蛇・深海特化コレクション';
    var DOOM_TITLE_JA = '☠ 冥獣・終末獣特化コレクション';
    var SKY_TITLE_JA = '🪽 天空・神鳥特化コレクション';

    function isArray(v){ return Object.prototype.toString.call(v) === '[object Array]'; }
    function titleOf(node){ return node && (node.title_ja || node.titleJa || node.title || node.label || ''); }
    function findByTitle(node, title){
      if (!node) return null;
      if (isArray(node)) {
        for (var i = 0; i < node.length; i++) {
          var got = findByTitle(node[i], title);
          if (got) return got;
        }
        return null;
      }
      if (typeof node === 'object') {
        if (titleOf(node) === title) return node;
        var keys = Object.keys(node);
        for (var j = 0; j < keys.length; j++) {
          var got2 = findByTitle(node[keys[j]], title);
          if (got2) return got2;
        }
      }
      return null;
    }
    function detachByTitle(arr, title){
      if (!isArray(arr)) return null;
      for (var i = 0; i < arr.length; i++) {
        var node = arr[i];
        if (titleOf(node) === title) return arr.splice(i, 1)[0];
        if (node && isArray(node.children)) {
          var got = detachByTitle(node.children, title);
          if (got) return got;
        }
      }
      return null;
    }
    function upsertDirect(arr, node, insertAt){
      if (!isArray(arr) || !node) return;
      var t = titleOf(node);
      for (var i = 0; i < arr.length; i++) {
        if (titleOf(arr[i]) === t) {
          arr[i] = node;
          return;
        }
      }
      if (typeof insertAt === 'number') arr.splice(insertAt, 0, node);
      else arr.push(node);
    }
    function normalizeOrder(arr, order){
      if (!isArray(arr)) return;
      arr.sort(function(a, b){
        var at = titleOf(a), bt = titleOf(b);
        var ai = order.indexOf(at), bi = order.indexOf(bt);
        if (ai === -1) ai = 999;
        if (bi === -1) bi = 999;
        if (ai !== bi) return ai - bi;
        return 0;
      });
    }

    var rootArr = db[ROLEPLAY_PARENT_KEY] || db['🎭 なりきりおすすめセット｜神獣・伝説なりきり'] || [];
