 var sinsNode = findByTitle(infernalRoot.children, '🩸 七つの大罪特化コレクション') || findByTitle(db, '🩸 七つの大罪特化コレクション');
 if (!sinsNode) {
 sinsNode = { title_ja: '🩸 七つの大罪特化コレクション', title_en: 'Deadly Sins Special Collections', children: [] };
 }

