/* === Final display-path repair: force Deadly Sins nodes into both grouped key and visible nested tree === */
(function(){
 "use strict";
 try {
 var db = (window.__PP_DB && window.__PP_DB.packs) || window.PRESET_PACKS_DB || window.__PRESET_PACKS_DB;
 if (!db || typeof db !== 'object') return;

 var ROLEPLAY_PARENT_KEY = '🎭 なりきりおすすめセット (Roleplay Recommended Sets)';
 var SINS_KEY = '🎭 なりきりおすすめセット｜職業・なりきり（深淵｜🩸 七つの大罪特化コレクション） (Deadly Sins Special Collections)';
 var ADMIN_KEY = '🎭 なりきりおすすめセット｜管理者専用なりきり (Admin-only Roleplay)';
 var INF_NAMED_KEY = '🎭 なりきりおすすめセット｜職業・なりきり（深淵｜固有名） (Infernal Named Personas)';
 var INF_TITLES_KEY = '🎭 なりきりおすすめセット｜職業・なりきり（深淵｜役職・称号） (Infernal Titles)';
 var INF_RANK_KEY = '🎭 なりきりおすすめセット｜職業・なりきり（深淵｜格・位階） (Infernal Rank)';

 function isArray(v){ return Object.prototype.toString.call(v) === '[object Array]'; }
 function titleOf(n){ return n && String(n.title_ja || n.titleJa || n.label || n.title || ''); }
 function clone(obj){ try { return JSON.parse(JSON.stringify(obj)); } catch(e){ return obj; } }
 function score(node){
 if (!node || typeof node !== 'object') return 0;
 var n = 1;
 if (isArray(node.children)) {
 for (var i=0;i<node.children.length;i++) n += score(node.children[i]);
 }
 return n;
 }
 function collectByTitle(node, title, out){
 if (!node) return;
 if (isArray(node)) {
 for (var i=0;i<node.length;i++) collectByTitle(node[i], title, out);
 return;
 }
 if (typeof node === 'object') {
 if (titleOf(node) === title) out.push(node);
 var keys = Object.keys(node);
 for (var j=0;j<keys.length;j++) collectByTitle(node[keys[j]], title, out);
 }
 }
 function bestNode(title){
 var found = [];
 collectByTitle(db, title, found);
 if (!found.length) return null;
 found.sort(function(a,b){ return score(b) - score(a); });
 return clone(found[0]);
 }
 function findByTitle(node, title){
 var arr = [];
 collectByTitle(node, title, arr);
 return arr[0] || null;
 }
 function removeChildrenByTitles(arr, titles){
 if (!isArray(arr)) return [];
 var out=[];
 for (var i=0;i<arr.length;i++) if (titles.indexOf(titleOf(arr[i])) < 0) out.push(arr[i]);
 return out;
 }
 function insertAfterTitle(arr, node, afterTitle){
 if (!isArray(arr) || !node) return arr;
 var t = titleOf(node);
 arr = removeChildrenByTitles(arr, [t]);
 var idx = -1;
 for (var i=0;i<arr.length;i++) if (titleOf(arr[i]) === afterTitle) { idx = i; break; }
 if (idx < 0) arr.push(node); else arr.splice(idx + 1, 0, node);
 return arr;
 }

 var sinTitles = [
 '🍽 ベルゼブブ（暴食）特化コレクション',
 '🌊 レヴィアタン（嫉妬）特化コレクション',
 '🛏 ベルフェゴール（怠惰）特化コレクション',
 '🔥 サタン（憤怒）特化コレクション',
 '💋 アスモデウス（色欲）特化コレクション',
 '🪽 ルシフェル（傲慢）特化コレクション'
 ];
 var sinChildren = [];
 for (var s=0;s<sinTitles.length;s++) {
 var node = bestNode(sinTitles[s]);
 if (node) sinChildren.push(node);
 }
 if (!sinChildren.length) return;

 // 1) Register the actual display-list key used by buildGroupedRoleplay.
 db[SINS_KEY] = sinChildren;

 // 2) Also force the already-built nested visible tree to the same children.
 var roleplayArr = db[ROLEPLAY_PARENT_KEY];
 if (isArray(roleplayArr) && roleplayArr.length) {
 var roleRoot = findByTitle(roleplayArr, '🎭 なりきり');
 var infernalRoot = roleRoot && findByTitle(roleRoot.children, '職業・なりきり（深淵）');
 if (infernalRoot) {
 var demonChildren = [];
 if (isArray(db[INF_NAMED_KEY])) demonChildren.push({ title_ja: '👤 固有名', title_en: 'Named Personas', children: clone(db[INF_NAMED_KEY]) });
 if (isArray(db[INF_TITLES_KEY])) demonChildren.push({ title_ja: '🏛 役職・称号', title_en: 'Titles', children: clone(db[INF_TITLES_KEY]) });
 if (isArray(db[INF_RANK_KEY])) demonChildren.push({ title_ja: '👑 格・位階', title_en: 'Rank', children: clone(db[INF_RANK_KEY]) });
 infernalRoot.children = [{
 title_ja: '🩸 七つの大罪特化コレクション',
 title_en: 'Deadly Sins Special Collections',
 children: sinChildren
 }];
 if (demonChildren.length) infernalRoot.children.push({
 title_ja: '👑 固有名魔王特化コレクション',
 title_en: 'Named Demon Lord Special Collections',
 children: demonChildren
 });
 }

 // 3) Restore admin-only roleplay node after Infernal if present/unlocked by prior data.
 var adminNode = null;
 if (isArray(db[ADMIN_KEY]) && db[ADMIN_KEY].length) adminNode = clone(db[ADMIN_KEY][0]);
 if (!adminNode) adminNode = bestNode('🛡 管理者専用なりきり特化コレクション');
 if (adminNode && roleRoot && isArray(roleRoot.children)) {
 roleRoot.children = insertAfterTitle(roleRoot.children, adminNode, '職業・なりきり（深淵）');
 }
 }

 if (window.__PP_DB) window.__PP_DB.packs = db;
 window.PRESET_PACKS_DB = db;
 window.__PRESET_PACKS_DB = db;
 } catch(e) {}
})();


